module traffic_light
(
    input rst_n,
    input clk,
    input pass_request,
    output [7:0] clock,
    output red
);

    reg [7:0] cnt;
    reg [1:0] state;

    parameter idle = 2'b00, s1_red = 2'b01, s2_yellow = 2'b10, s3_green = 2'b11;

    assign red = (state == s1_red) ? 1 : 0;
    assign yellow = (state == s2_yellow) ? 1 : 0;
    assign green = (state == s3_green) ? 1 : 0;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state <= idle;
            cnt <= 0;
        end else begin
            case (state)
                idle: begin
                    state <= s3_green;
                end
                s1_red: begin
                    if (cnt == 3) begin
                        state <= s3_green;
                        cnt <= 60;
                    end else begin
                        cnt <= cnt - 1;
                    end
                end
                s2_yellow: begin
                    if (cnt == 3) begin
                        state <= s1_red;
                        cnt <= 10;
                    end else begin
                        cnt <= cnt - 1;
                    end
                end
                s3_green: begin
                    if (cnt == 3) begin
                        state <= s2_yellow;
                        cnt <= 5;
                    end else begin
                        cnt <= cnt - 1;
                    end
                end
            endcase
        end
    end

    assign clock = cnt;

endmodule
